---
import { cn } from "@/lib/utils";
import type { HTMLAttributes } from "astro/types";

type TooltipSide =
  | "top"
  | "bottom"
  | "left"
  | "right"
  | "inline-start"
  | "inline-end";

interface Props extends HTMLAttributes<"div"> {
  class?: string;
  sideOffset?: number;
  side?: TooltipSide;
  align?: "start" | "center" | "end";
  alignOffset?: number;
}

const {
  class: className = "",
  sideOffset,
  side = "top",
  align = "center",
  alignOffset,
  ...rest
} = Astro.props as Props;
---

<div data-slot="tooltip-portal">
  <div data-slot="tooltip-positioner" class="isolate z-50">
    <div
      {...rest}
      hidden
      data-slot="tooltip-content"
      data-side={side}
      data-side-offset={sideOffset}
      data-align={align}
      data-align-offset={alignOffset}
      class={cn(
        "relative pointer-events-none data-open:pointer-events-auto data-closed:pointer-events-none data-open:animate-in data-open:fade-in-0 data-open:zoom-in-95 data-[state=delayed-open]:animate-in data-[state=delayed-open]:fade-in-0 data-[state=delayed-open]:zoom-in-95 data-closed:animate-out data-closed:fade-out-0 data-closed:zoom-out-95 data-[side=bottom]:slide-in-from-top-2 data-[side=left]:slide-in-from-right-2 data-[side=right]:slide-in-from-left-2 data-[side=top]:slide-in-from-bottom-2 inline-flex items-center gap-1.5 rounded-none px-3 py-1.5 text-xs has-data-[slot=kbd]:pr-1.5 **:data-[slot=kbd]:relative **:data-[slot=kbd]:isolate **:data-[slot=kbd]:z-50 **:data-[slot=kbd]:rounded-none data-[side=inline-start]:slide-in-from-right-2 data-[side=inline-end]:slide-in-from-left-2 z-50 w-fit max-w-xs origin-(--transform-origin) bg-foreground text-background",
        className,
      )}
    >
      <slot />
      <div
        data-slot="tooltip-arrow"
        class={cn(
          "absolute size-2.5 rotate-45 rounded-none data-[side=top]:-bottom-1 data-[side=bottom]:-top-1 data-[side=left]:-right-1 data-[side=right]:-left-1 data-[side=inline-start]:-right-1 data-[side=inline-end]:-left-1 z-50 bg-foreground fill-foreground",
          "data-[side=top]:-bottom-1",
          "data-[side=bottom]:-top-1",
          "data-[side=left]:-right-1",
          "data-[side=right]:-left-1",
        )}
      >
      </div>
    </div>
  </div>
</div>

---
import { cn } from "@/lib/utils";
import type { HTMLAttributes } from "astro/types";

interface Props extends HTMLAttributes<"button"> {
  class?: string;
  /** Radix-like: render wrapper so the child can be the interactive element */
  asChild?: boolean;
}

const {
  class: className = "",
  asChild = false,
  type = "button",
  ...rest
} = Astro.props as Props;
---

{
  asChild ? (
    <div data-slot="tooltip-trigger" data-as-child class={cn("", className)}>
      <slot />
    </div>
  ) : (
    <button
      {...rest}
      type={type}
      data-slot="tooltip-trigger"
      class={cn("", className)}
    >
      <slot />
    </button>
  )
}

export { default as Tooltip } from "./Tooltip.astro";
export { default as TooltipTrigger } from "./TooltipTrigger.astro";
export { default as TooltipContent } from "./TooltipContent.astro";
